const archivos = $input.all();
const ahora = Date.now();

const staticData = $getWorkflowStaticData('global');
if (!staticData.procesados) staticData.procesados = {}; // { fileId: modifiedTime }

// Nuevo si: fileId nunca visto, o modifiedTime cambio (reemplazo).
const nuevos = archivos.filter(item => {
  const id = item.json.id;
  const mt = item.json.modifiedTime;
  const prev = staticData.procesados[id];
  return !prev || prev !== mt;
});

// Marcar como procesados solo despues del POST exitoso -> aca los pasamos
// pero los marcamos en un nodo posterior. Guardamos {id, mt} para procesarlos.

if (nuevos.length === 0) return [];

return nuevos.map(item => ({
  json: {
    fileId: item.json.id,
    nombre: item.json.name,
    modifiedTime: item.json.modifiedTime,
    createdTime: item.json.createdTime,
    sizeBytes: parseInt(item.json.size || '0', 10),
    mimeType: item.json.mimeType,
  }
}));

// Convertimos el binario a base64 para postear al server
const out = [];
for (const item of $input.all()) {
  const bin = item.binary?.data;
  if (!bin) continue;
  const b64 = bin.data; // n8n ya trae el binario en base64
  const meta = item.json;
  out.push({
    json: {
      fileId: meta.fileId,
      nombre: meta.nombre,
      modifiedTime: meta.modifiedTime,
      sizeBytes: meta.sizeBytes,
      contentBase64: b64,
    }
  });
}
return out;

// Marcar como procesados los que llegaron aca (post OK)
const staticData = $getWorkflowStaticData('global');
if (!staticData.procesados) staticData.procesados = {};
let marcados = 0;
for (const item of $input.all()) {
  const resp = item.json;
  // El server nos devuelve el fileId original en la respuesta? Puede que no. Buscamos por accion.
  // Como el node anterior emitio {fileId, nombre, modifiedTime}, tomamos el binding del item previo si hay.
  // Alternativa robusta: el HTTP Request node en n8n trae el json de input y output.
  // Guardamos por indice: el i-esimo output corresponde al i-esimo input.
}
// Enfoque simple: iterar sobre el input original de 'Convertir a base64' via workflow context.
const originales = $('Convertir a base64').all();
for (const orig of originales) {
  staticData.procesados[orig.json.fileId] = orig.json.modifiedTime;
  marcados++;
}
return [{ json: { marcados } }];
